#include <stdio.h>

int main() {
  int x = 42;
  int *ptr = &x;
  printf("Value of x: %d\n", x);
  printf("Address of x: %p\n", &x);
  printf("Pointer points to address: %p\n", ptr);
  printf("Value via pointer: %d\n", *ptr);
  *ptr = 100;
  printf("x after modification: %d\n", x);
  return 0;
}
